#!/bin/bash
# Auto root
if [ "$EUID" -ne 0 ]; then
    echo "[+] Switching to root..."
    exec sudo bash "$0" "$@"
fi

set -e

WORKDIR="/etc/sni-proxy"
BINARY_PATH="$WORKDIR/sni-proxy"
CONFIG_PATH="$WORKDIR/config.json"
SERVICE_PATH="/etc/systemd/system/sni.service"

YELLOW='\033[1;33m'
GREEN='\033[0;32m'
RED='\033[0;31m'
NC='\033[0m'

mkdir -p "$WORKDIR"

echo -e "${YELLOW}[+] Installing binary...${NC}"

cat > /tmp/sni-proxy.b64 <<'EOF_B64'


EOF_B64

base64 -d /tmp/sni-proxy.b64 > "$BINARY_PATH"
chmod +x "$BINARY_PATH"
rm -f /tmp/sni-proxy.b64

setup_config() {
    clear
    echo -e "${YELLOW}--- Configuration Setup ---${NC}"

    read -p "Enter Listen Host [0.0.0.0]: " L_HOST
    L_HOST=${L_HOST:-"0.0.0.0"}

    read -p "Enter Listen Port [40443]: " L_PORT
    L_PORT=${L_PORT:-40443}

    read -p "Enter Connect IP [104.18.4.130]: " C_IP
    C_IP=${C_IP:-"104.18.4.130"}

    read -p "Enter Connect Port [443]: " C_PORT
    C_PORT=${C_PORT:-443}

    read -p "Enter Fake SNI [security.vercel.com]: " F_SNI
    F_SNI=${F_SNI:-"security.vercel.com"}

    echo
    echo -e "${YELLOW}Testing Connectivity...${NC}"
    echo -e "${YELLOW}Pinging Connect IP: $C_IP${NC}"
    ping -c 3 "$C_IP" || true

    echo
    echo -e "${YELLOW}Pinging Fake SNI: $F_SNI${NC}"
    ping -c 3 "$F_SNI" || true

    cat > "$CONFIG_PATH" <<EOC
{
  "LISTEN_HOST": "$L_HOST",
  "LISTEN_PORT": $L_PORT,
  "CONNECT_IP": "$C_IP",
  "CONNECT_PORT": $C_PORT,
  "FAKE_SNI": "$F_SNI"
}
EOC
}

create_service() {
    cat > "$SERVICE_PATH" <<EOC
[Unit]
Description=SNI Proxy Service
After=network.target

[Service]
Type=simple
User=root
WorkingDirectory=$WORKDIR
ExecStart=$BINARY_PATH
Restart=always

[Install]
WantedBy=multi-user.target
EOC

    systemctl daemon-reload
    systemctl enable sni
    systemctl restart sni
}

cat > /usr/local/bin/sni-reconfig.sh <<'EOM'
#!/bin/bash
CONFIG_PATH="/etc/sni-proxy/config.json"

YELLOW='\033[1;33m'
NC='\033[0m'

clear
echo -e "${YELLOW}--- Configuration Setup ---${NC}"

read -p "Enter Listen Host [0.0.0.0]: " L_HOST
L_HOST=${L_HOST:-"0.0.0.0"}

read -p "Enter Listen Port [40443]: " L_PORT
L_PORT=${L_PORT:-40443}

read -p "Enter Connect IP [104.18.4.130]: " C_IP
C_IP=${C_IP:-"104.18.4.130"}

read -p "Enter Connect Port [443]: " C_PORT
C_PORT=${C_PORT:-443}

read -p "Enter Fake SNI [security.vercel.com]: " F_SNI
F_SNI=${F_SNI:-"security.vercel.com"}

echo
echo -e "${YELLOW}Testing Connectivity...${NC}"
ping -c 3 "$C_IP" || true
ping -c 3 "$F_SNI" || true

cat > "$CONFIG_PATH" <<EOC
{
  "LISTEN_HOST": "$L_HOST",
  "LISTEN_PORT": $L_PORT,
  "CONNECT_IP": "$C_IP",
  "CONNECT_PORT": $C_PORT,
  "FAKE_SNI": "$F_SNI"
}
EOC

systemctl restart sni
EOM

chmod +x /usr/local/bin/sni-reconfig.sh

cat > /usr/local/bin/sni <<'EOM'
#!/bin/bash
while true; do
    clear
    echo -e "\033[0;32m====================================\033[0m"
    echo -e "\033[0;32m       SNI Proxy Manager            \033[0m"
    echo -e "\033[0;32m====================================\033[0m"
    echo "1) Show Status"
    echo "2) Start Service"
    echo "3) Stop Service"
    echo "4) Restart Service"
    echo "5) Configuration Setup"
    echo "6) View Live Logs (Anonymous)"
    echo "7) Uninstall"
    echo "8) Exit"
    read -p "Choice [1-8]: " choice
    case $choice in
        1) systemctl status sni; read -p "Press Enter...";;
        2) systemctl start sni;;
        3) systemctl stop sni;;
        4) systemctl restart sni;;
        5) /usr/local/bin/sni-reconfig.sh;;
        6) journalctl -u sni -f -o cat;;
        7) systemctl stop sni
           systemctl disable sni
           rm -rf /etc/sni-proxy
           rm -f /usr/local/bin/sni*
           rm -f /etc/systemd/system/sni.service
           systemctl daemon-reload
           echo "Uninstalled"
           exit;;
        8) exit;;
    esac
done
EOM

chmod +x /usr/local/bin/sni

setup_config
create_service

echo -e "${GREEN}[✓] Installation complete! Type 'sni'${NC}"
